const POSTEX_BASE_URL = "https://api.postex.pk/services/v1";

export type PostExStatus = {
  status: string;
  statusDetail: string;
  trackingNumber: string;
  shippingCost: number;
  codFee: number;
};

/**
 * Fetches the latest tracking status from PostEx API
 */
export async function getPostExTracking(trackingNumber: string): Promise<PostExStatus | null> {
  const token = process.env.GLOWVE_POSTEX_TOKEN;
  if (!token) {
    console.error("PostEx token not configured.");
    return null;
  }

  try {
    const response = await fetch(`${POSTEX_BASE_URL}/track-order/${trackingNumber}`, {
      method: "GET",
      headers: {
        token: token,
        "Content-Type": "application/json",
      },
    });

    if (!response.ok) {
      console.error(`PostEx API error: ${response.status}`);
      return null;
    }

    const data = await response.json();

    // PostEx returns { statusCode: "200", statusMessage: "Success", dist: { ... } }
    if (data.statusCode === "200" && data.dist) {
      return {
        status: data.dist.orderStatus,
        statusDetail: data.dist.transactionStatus || data.dist.orderStatus,
        trackingNumber: trackingNumber,
        shippingCost: Number(data.dist.serviceCharges || 0),
        codFee: Number(data.dist.codCharges || 0),
      };
    }

    return null;
  } catch (error) {
    console.error("Failed to fetch PostEx tracking:", error);
    return null;
  }
}

/**
 * Maps PostEx status strings to our internal Order status
 */
export function mapPostExStatus(postexStatus: string): "dispatched" | "delivered" | "returned" | "confirmed" {
  const s = postexStatus.toLowerCase();

  if (s.includes("delivered")) return "delivered";
  if (s.includes("return") || s.includes("rto")) return "returned";
  if (s.includes("cancel")) return "returned"; // Cancelled usually means didn't deliver
  if (s.includes("shipped") || s.includes("transit") || s.includes("out for delivery")) return "dispatched";

  return "dispatched"; // Default to dispatched if we have a tracking number but status is unclear
}

import { batches, batchMovements, orderItems } from "./db/schema";
import { eq, asc, and, gt, sql } from "drizzle-orm";
import { db } from "./db";

type DbTransaction = Parameters<Parameters<typeof db.transaction>[0]>[0];

/**
 * Allocates stock for a given SKU using FIFO logic (oldest expiry date first).
 * MUST be called within a database transaction.
 * 
 * @param tx The Drizzle transaction object
 * @param skuId The ID of the SKU being ordered
 * @param quantityRequired Total number of units required
 * @param orderId The ID of the newly created order
 * @param salePrice Price per unit for this order item
 * @param codAmount COD amount assigned to this specific item (often 0 if paid, or full price)
 */
export async function allocateStock(
  tx: DbTransaction,
  skuId: string,
  quantityRequired: number,
  orderId: string,
  salePrice: number,
  codAmount: number
) {
  let remainingToAllocate = quantityRequired;

  // 1. Find all active batches for this SKU, ordered by closest expiry date (FIFO)
  const activeBatches = await tx
    .select()
    .from(batches)
    .where(and(eq(batches.skuId, skuId), gt(batches.unitsRemaining, 0)))
    .orderBy(asc(batches.expiryDate));

  // 2. Calculate total available stock to ensure we can fulfill the order
  const totalAvailable = activeBatches.reduce((sum: number, b: typeof batches.$inferSelect) => sum + b.unitsRemaining, 0);

  if (totalAvailable < quantityRequired) {
    throw new Error(`Insufficient stock for SKU ${skuId}. Required: ${quantityRequired}, Available: ${totalAvailable}`);
  }

  // 3. Iterate through batches and deduct stock
  for (const batch of activeBatches) {
    if (remainingToAllocate <= 0) break;

    const unitsToTakeFromThisBatch = Math.min(batch.unitsRemaining, remainingToAllocate);

    // Deduct from batch
    await tx
      .update(batches)
      .set({
        unitsRemaining: sql`${batches.unitsRemaining} - ${unitsToTakeFromThisBatch}`,
      })
      .where(eq(batches.id, batch.id));

    // Create BatchMovement record (audit trail)
    await tx.insert(batchMovements).values({
      batchId: batch.id,
      movementType: "dispatch",
      quantityChange: -unitsToTakeFromThisBatch, // Negative because stock is leaving
      referenceId: orderId,
      notes: "Auto-allocated by FIFO engine",
    });

    // Create OrderItem record linking the specific batch to the order
    await tx.insert(orderItems).values({
      orderId,
      skuId,
      batchId: batch.id,
      quantity: unitsToTakeFromThisBatch,
      salePrice: salePrice.toString(),
      codAmount: codAmount.toString(),
    });

    remainingToAllocate -= unitsToTakeFromThisBatch;
  }

  // Double check
  if (remainingToAllocate > 0) {
    throw new Error("Failed to allocate full quantity despite adequate total stock. Concurrency issue?");
  }
}

"""Zoho Recruit API client. Handles OAuth, candidate fetching, attachment download, status updates."""
from __future__ import annotations
import time

import requests

DC_HOSTS = {
    "com": ("https://accounts.zoho.com", "https://recruit.zoho.com"),
    "eu": ("https://accounts.zoho.eu", "https://recruit.zoho.eu"),
    "in": ("https://accounts.zoho.in", "https://recruit.zoho.in"),
    "com.au": ("https://accounts.zoho.com.au", "https://recruit.zoho.com.au"),
    "sa": ("https://accounts.zoho.sa", "https://recruit.zoho.sa"),
    "jp": ("https://accounts.zoho.jp", "https://recruit.zoho.jp"),
}

SCOPES = ",".join([
    "ZohoRecruit.modules.candidate.READ",
    "ZohoRecruit.modules.application.READ",
    "ZohoRecruit.modules.application.UPDATE",
    "ZohoRecruit.modules.interview.READ",
    "ZohoRecruit.modules.interview.CREATE",
    "ZohoRecruit.users.READ",
    "ZohoRecruit.modules.notes.CREATE",
    "ZohoRecruit.modules.notes.READ",
])


class ZohoClient:
    def __init__(self, client_id: str, client_secret: str, refresh_token: str, data_center: str = "com"):
        if data_center not in DC_HOSTS:
            raise ValueError(f"Unknown data center {data_center!r}. Valid: {list(DC_HOSTS)}")
        self.client_id = client_id
        self.client_secret = client_secret
        self.refresh_token = refresh_token
        self.accounts_host, self.api_host = DC_HOSTS[data_center]
        self._access_token: str | None = None
        self._access_token_expires_at: float = 0.0

    @property
    def api_base(self) -> str:
        return f"{self.api_host}/recruit/v2"

    def _ensure_access_token(self) -> str:
        if self._access_token and time.time() < self._access_token_expires_at - 60:
            return self._access_token
        if not self.refresh_token:
            raise RuntimeError("No refresh token. Run: python recruit.py auth")
        resp = requests.post(
            f"{self.accounts_host}/oauth/v2/token",
            data={
                "refresh_token": self.refresh_token,
                "client_id": self.client_id,
                "client_secret": self.client_secret,
                "grant_type": "refresh_token",
            },
            timeout=30,
        )
        resp.raise_for_status()
        data = resp.json()
        if "access_token" not in data:
            raise RuntimeError(f"Token refresh failed: {data}")
        self._access_token = data["access_token"]
        self._access_token_expires_at = time.time() + int(data.get("expires_in", 3600))
        return self._access_token

    def _headers(self) -> dict:
        return {"Authorization": f"Zoho-oauthtoken {self._ensure_access_token()}"}

    def list_job_openings(self) -> list[dict]:
        return self._paginated(f"{self.api_base}/Job_Openings")

    def find_job_opening_id(self, posting_title: str) -> str | None:
        for jo in self.list_job_openings():
            if jo.get("Posting_Title") == posting_title:
                return jo["id"]
        return None

    def list_candidates_for_job(self, job_id: str) -> list[dict]:
        """Returns Candidates associated with the given job_id."""
        return self._paginated(f"{self.api_base}/Job_Openings/{job_id}/associate")

    def list_applications_for_role(self, posting_title: str) -> list[dict]:
        """Returns Application records whose Posting_Title matches."""
        apps = self._paginated(f"{self.api_base}/Applications")
        return [a for a in apps if a.get("Posting_Title") == posting_title]

    def get_candidate(self, candidate_id: str) -> dict:
        url = f"{self.api_base}/Candidates/{candidate_id}"
        resp = requests.get(url, headers=self._headers(), timeout=30)
        if resp.status_code == 204:
            return {}
        resp.raise_for_status()
        rows = resp.json().get("data", [])
        return rows[0] if rows else {}

    def list_attachments(self, candidate_id: str) -> list[dict]:
        url = f"{self.api_base}/Candidates/{candidate_id}/Attachments"
        resp = requests.get(url, headers=self._headers(), timeout=30)
        if resp.status_code == 204:
            return []
        resp.raise_for_status()
        return resp.json().get("data", [])

    def download_attachment(self, candidate_id: str, attachment_id: str) -> bytes:
        url = f"{self.api_base}/Candidates/{candidate_id}/Attachments/{attachment_id}"
        resp = requests.get(url, headers=self._headers(), timeout=60)
        resp.raise_for_status()
        return resp.content

    def update_candidate_status(self, candidate_id: str, status: str) -> dict:
        url = f"{self.api_base}/Candidates/{candidate_id}"
        resp = requests.put(
            url,
            headers={**self._headers(), "Content-Type": "application/json"},
            json={"data": [{"Candidate_Status": status}]},
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json()

    def update_application_pipeline(self, application_id: str, stage: str) -> dict:
        url = f"{self.api_base}/Applications/{application_id}"
        resp = requests.put(
            url,
            headers={**self._headers(), "Content-Type": "application/json"},
            json={"data": [{"Hiring_Pipeline": stage}]},
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json()

    def get_users(self) -> list[dict]:
        """Returns all active Zoho Recruit users."""
        url = f"{self.api_host}/recruit/v2/users"
        resp = requests.get(url, headers=self._headers(), params={"type": "ActiveUsers"}, timeout=30)
        resp.raise_for_status()
        return resp.json().get("users", [])

    def search_applications(self, candidate_id: str, job_id: str) -> list[dict]:
        """Search for Applications matching a candidate and job opening."""
        url = f"{self.api_base}/Applications/search"
        criteria = f"(Candidate:equals:{candidate_id})and(Job_Opening:equals:{job_id})"
        resp = requests.get(
            url,
            headers=self._headers(),
            params={"criteria": criteria},
            timeout=30
        )
        if resp.status_code == 204:
            return []
        resp.raise_for_status()
        return resp.json().get("data", [])

    def create_interview(self, data: dict) -> dict:
        """Create a new record in the Interviews module."""
        url = f"{self.api_base}/Interviews"
        resp = requests.post(
            url,
            headers={**self._headers(), "Content-Type": "application/json"},
            json={"data": [data]},
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json()

    def create_note(self, parent_id: str, module: str, title: str, content: str) -> dict:
        """Create a note associated with a record."""
        url = f"{self.api_base}/Notes"
        resp = requests.post(
            url,
            headers={**self._headers(), "Content-Type": "application/json"},
            json={
                "data": [
                    {
                        "Note_Title": title,
                        "Note_Content": content,
                        "Parent_Id": parent_id,
                        "se_module": module
                    }
                ]
            },
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json()

    def _paginated(self, url: str, data_key: str = "data") -> list[dict]:
        out: list[dict] = []
        page = 1
        while True:
            resp = requests.get(
                url,
                headers=self._headers(),
                params={"page": page, "per_page": 200},
                timeout=30,
            )
            if resp.status_code == 204:
                break
            resp.raise_for_status()
            payload = resp.json()
            out.extend(payload.get(data_key, []))
            info = payload.get("info", {})
            if not info.get("more_records"):
                break
            page += 1
        return out


def exchange_self_client_code(client_id: str, client_secret: str, code: str, data_center: str) -> str:
    """Exchange a Self Client grant code for a refresh_token."""
    accounts_host, _ = DC_HOSTS[data_center]
    resp = requests.post(
        f"{accounts_host}/oauth/v2/token",
        data={
            "code": code,
            "client_id": client_id,
            "client_secret": client_secret,
            "grant_type": "authorization_code",
        },
        timeout=30,
    )
    resp.raise_for_status()
    data = resp.json()
    if "refresh_token" not in data:
        raise RuntimeError(
            f"No refresh_token in response: {data}\n"
            "Possible causes: code expired (10 min), code already used, or scopes don't match what was generated."
        )
    return data["refresh_token"]
